  1	import * as React from 'react';
  2	import { IRow, ThProps } from '@patternfly/react-table';
  3	import { Workload } from 'types/Workload';
  4	import { Card, CardBody, Grid, GridItem, Tab, Tabs, Title, TitleSizes } from '@patternfly/react-core';
  5	import { activeTab } from '../../components/Tab/Tabs';
  6	import { RenderComponentScroll } from 'components/Nav/Page';
  7	import { location, router } from '../../app/History';
  8	import {
  9	  tabName as workloadTabName,
 10	  defaultTab as workloadDefaultTab
 11	} from '../../pages/WorkloadDetails/WorkloadDetailsPage';
 12	import { subTabStyle } from 'styles/TabStyles';
 13	import { kialiStyle } from '../../styles/StyleUtils';
 14	import { t } from 'i18next';
 15	import { SimpleTable } from '../Table/SimpleTable';
 16	import { WaypointWorkloadsTable } from './WaypointWorkloadsTable';
 17	import { WaypointForLabel, WaypointType } from '../../types/Ambient';
 18	import { PodStatus } from '../../pages/WorkloadDetails/PodStatus';
 19	
 20	const resources: string[] = ['service', 'workload', 'information'];
 21	
 22	const waypointTabs = ['service', 'workload', 'information'];
 23	const tabName = 'waypointTab';
 24	
 25	type WaypointConfigProps = {
 26	  workload: Workload;
 27	};
 28	
 29	const fullHeightStyle = kialiStyle({
 30	  height: '100%'
 31	});
 32	
 33	export const isWaypointFor = (wk: Workload): string => {
 34	  switch (wk.labels[WaypointForLabel]) {
 35	    case WaypointType.All:
 36	      return WaypointType.All;
 37	    case WaypointType.None:
 38	      return WaypointType.None;
 39	    case WaypointType.Workload:
 40	      return WaypointType.Workload;
 41	    default:
 42	      return WaypointType.Service;
 43	  }
 44	};
 45	
 46	const showProxyStatus = (workload: Workload): React.ReactNode => {
 47	  const cols: ThProps[] = [
 48	    { title: 'Pod Name' },
 49	    { title: 'CDS' },
 50	    { title: 'LDS' },
 51	    { title: 'EDS' },
 52	    { title: 'RDS' }
 53	  ];
 54	
 55	  const rows: IRow[] = workload.pods.map(pod => {
 56	    const podDetails = (
 57	      <>
 58	        <span style={{ marginRight: '1em' }}>{pod.name}</span> <PodStatus proxyStatus={pod.proxyStatus} />
 59	      </>
 60	    );
 61	    return {
 62	      cells: [podDetails, pod.proxyStatus?.CDS, pod.proxyStatus?.LDS, pod.proxyStatus?.EDS, pod.proxyStatus?.RDS]
 63	    };
 64	  });
 65	
 66	  return <SimpleTable label={'Proxy Status'} columns={cols} rows={rows} />;
 67	};
 68	
 69	export const WaypointConfig: React.FC<WaypointConfigProps> = (props: WaypointConfigProps) => {
 70	  const waypointFor = isWaypointFor(props.workload);
 71	  let defaultTab: string;
 72	  switch (waypointFor) {
 73	    case WaypointType.None:
 74	      defaultTab = 'information';
 75	      break;
 76	    case WaypointType.Workload:
 77	      defaultTab = WaypointType.Workload;
 78	      break;
 79	    default:
 80	      defaultTab = WaypointType.Service;
 81	  }
 82	  const [activeKey, setActiveKey] = React.useState(waypointTabs.indexOf(activeTab(tabName, defaultTab)));
 83	  const [resource, setResource] = React.useState(activeTab(tabName, defaultTab));
 84	
 85	  const currentTabIndexRef = React.useRef();
 86	  const resourceRef = React.useRef();
 87	
 88	  React.useEffect(() => {
 89	    const currentTabIndex = waypointTabs.indexOf(activeTab(tabName, defaultTab));
 90	
 91	    if (
 92	      resourceRef.current !== undefined &&
 93	      resource !== resourceRef.current &&
 94	      currentTabIndexRef.current !== undefined &&
 95	      currentTabIndexRef.current !== currentTabIndex
 96	    ) {
 97	      if (currentTabIndex !== activeKey) {
 98	        setActiveKey(currentTabIndex);
 99	      }
100	      // @ts-ignore
101	      currentTabIndexRef.current = currentTabIndex;
102	      // @ts-ignore
103	      resourceRef.current = resource;
104	    }
105	  }, [resource, activeKey, defaultTab]);
106	
107	  const waypointHandleTabClick = (_event: React.MouseEvent, tabIndex: string | number): void => {
108	    const resourceIdx: number = +tabIndex;
109	    const targetResource: string = resources[resourceIdx];
110	
111	    if (targetResource !== resource) {
112	      setResource(targetResource);
113	      setActiveKey(resourceIdx);
114	
115	      const mainTab = new URLSearchParams(location.getSearch()).get(workloadTabName) ?? workloadDefaultTab;
116	      const urlParams = new URLSearchParams(location.getSearch());
117	      urlParams.set(tabName, targetResource);
118	      urlParams.set(workloadTabName, mainTab);
119	      router.navigate(`${location.getPathname()}?${urlParams.toString()}`);
120	    }
121	  };
122	
123	  const tabs: JSX.Element[] = [];
124	
125	  if (waypointFor === WaypointType.Service || waypointFor === WaypointType.All) {
126	    const servicesTab = (
127	      <Tab title={t('Services')} eventKey={0} key={waypointFor}>
128	        <Card className={fullHeightStyle}>
129	          <CardBody>
130	            <div className={fullHeightStyle}>
131	              <div style={{ marginBottom: '1.25rem' }}>
132	                <WaypointWorkloadsTable
133	                  workloads={props.workload.waypointServices ? props.workload.waypointServices : []}
134	                  type={WaypointType.Service}
135	                />
136	              </div>
137	            </div>
138	          </CardBody>
139	        </Card>
140	      </Tab>
141	    );
142	    tabs.push(servicesTab);
143	  }
144	
145	  if (waypointFor === WaypointType.Workload || waypointFor === WaypointType.All) {
146	    const workloadsTab = (
147	      <Tab title={t('Workloads')} eventKey={1} key={waypointFor}>
148	        <Card className={fullHeightStyle}>
149	          <CardBody>
150	            <div className={fullHeightStyle}>
151	              <div style={{ marginBottom: '1.25rem' }}>
152	                <WaypointWorkloadsTable
153	                  workloads={props.workload.waypointWorkloads ? props.workload.waypointWorkloads : []}
154	                  type={WaypointType.Workload}
155	                />
156	              </div>
157	            </div>
158	          </CardBody>
159	        </Card>
160	      </Tab>
161	    );
162	    tabs.push(workloadsTab);
163	  }
164	
165	  const infoTab = (
166	    <Tab title={t('Info')} eventKey={2} key="information">
167	      <Card className={fullHeightStyle}>
168	        <CardBody>
169	          <div className={fullHeightStyle}>
170	            <div style={{ marginBottom: '1.25rem' }}>
171	              <Title
172	                headingLevel="h5"
173	                size={TitleSizes.md}
174	                style={{ marginBottom: '1em' }}
175	                data-test="waypointfor-title"
176	              >
177	                Waypoint for: {waypointFor}
178	              </Title>
179	              {showProxyStatus(props.workload)}
180	            </div>
181	          </div>
182	        </CardBody>
183	      </Card>
184	    </Tab>
185	  );
186	  tabs.push(infoTab);
187	
188	  return (
189	    <RenderComponentScroll>
190	      <Grid>
191	        <GridItem span={12}>
192	          <Tabs
193	            id="waypoint-details"
194	            className={subTabStyle}
195	            activeKey={activeKey}
196	            onSelect={waypointHandleTabClick}
197	            mountOnEnter={true}
198	            unmountOnExit={true}
199	          >
200	            {tabs}
201	          </Tabs>
202	        </GridItem>
203	      </Grid>
204	    </RenderComponentScroll>
205	  );
206	};

